select 
from motor_insurance

    and ID = #{id}
    and creator_employee_no = #{creatorEmployeeNo}
    and Date_start_contract = #{dateStartContract}
    and Date_last_renewal = #{dateLastRenewal}
    and Date_next_renewal = #{dateNextRenewal}
    and Date_birth = #{dateBirth}
    and Date_driving_licence = #{dateDrivingLicence}
    and Type_risk = #{typeRisk}
    and Area = #{area}
    and Distribution_channel = #{distributionChannel}
    and Seniority = #{seniority}
    and Policies_in_force = #{policiesInForce}
    and Max_policies = #{maxPolicies}
    and Max_products = #{maxProducts}
    and Lapse = #{lapse}
    and Date_lapse = #{dateLapse}
    and Payment = #{payment}
    and Premium = #{premium}
    and Second_driver = #{secondDriver}

order by ID desc

